const body = $input.first().json.body;

const project = (body.project || '').trim().toLowerCase().replace(/\s+/g, '-');
const action = body.action || 'synthesize';
const feedback = body.feedback || '';
const currentVersion = parseInt(body.current_version) || 0;

if (!project) throw new Error('project name is required');
if (!['synthesize', 'approve'].includes(action)) throw new Error('action must be synthesize or approve');

const workspacePath = `/home/node/workspace/${project}`;
const version = action === 'approve' ? currentVersion : currentVersion + 1;

return [{
  json: {
    project,
    action,
    feedback,
    currentVersion,
    version,
    workspacePath,
    interviewHandoff: `${workspacePath}/handoffs/002-prd-interview.md`,
    analysisHandoff: `${workspacePath}/handoffs/001-analysis-complete.md`,
    handoffPath: `${workspacePath}/handoffs/003-prd-refined.md`,
    prdDir: `${workspacePath}/tasks`
  }
}];

const fs = require('fs');
const data = $('Code - Validate Inputs').first().json;
const version = data.currentVersion;
const prdPath = `${data.prdDir}/prd-${data.project}-v${version}.md`;

let prd;
try {
  prd = fs.readFileSync(prdPath, 'utf8');
} catch(e) {
  return [{ json: { valid: false, errors: [`PRD v${version} not found at ${prdPath}. Synthesize the PRD first.`], project: data.project, version } }];
}

const errors = [];

// Frontmatter
const fmMatch = prd.match(/^---\n([\s\S]*?)\n---/);
if (!fmMatch) {
  errors.push('Missing YAML frontmatter');
} else {
  const fm = fmMatch[1];
  if (!/phase:\s*prd-synthesis/.test(fm)) errors.push('frontmatter: phase must be prd-synthesis');
  if (!/version:\s*v\d+/.test(fm)) errors.push('frontmatter: version missing or malformed (expected v1, v2, etc.)');
  if (!/status:\s/.test(fm)) errors.push('frontmatter: status field missing');
}

// Required sections (1-7 always) — accept # or ## headings
const sectionChecks = [
  [/#{1,3}\s+(?:\d+\.\s+)?Executive Summary/i, 'Section 1: Executive Summary'],
  [/#{1,3}\s+(?:\d+\.\s+)?Functional Requirements/i, 'Section 2: Functional Requirements'],
  [/#{1,3}\s+(?:\d+\.\s+)?Non-Functional Requirements/i, 'Section 3: Non-Functional Requirements'],
  [/#{1,3}\s+(?:\d+\.\s+)?User Stories/i, 'Section 4: User Stories'],
  [/#{1,3}\s+(?:\d+\.\s+)?Architecture/i, 'Section 5: Architecture Recommendations'],
  [/#{1,3}\s+(?:\d+\.\s+)?Risk/i, 'Section 6: Risk Assessment'],
  [/#{1,3}\s+(?:\d+\.\s+)?MVP/i, 'Section 7: MVP vs. Future Phases'],
];
for (const [pattern, name] of sectionChecks) {
  if (!pattern.test(prd)) errors.push(`Missing ${name}`);
}

// FR count
const frCount = (prd.match(/\*\*FR-\d+:/g) || []).length;
if (frCount < 3) errors.push(`Fewer than 3 FRs (found ${frCount}) — need at least 3`);

// NFR numeric target
const nfrSection = prd.match(/#{1,3}\s+(?:\d+\.\s+)?Non-Functional[\s\S]*?(?=\n#{1,3}\s)/i)?.[0] || '';
if (nfrSection && !/ \d+\s*(?:ms|s|%|concurrent|users|GB|MB|KiB|year|hour)/.test(nfrSection)) {
  errors.push('NFR section lacks numeric targets (e.g. < 200ms, 99.9%, 500 users)');
}

// User story count
const usCount = (prd.match(/\*\*US-\d+:/g) || []).length;
if (usCount < 3) errors.push(`Fewer than 3 user stories (found ${usCount}) — need at least 3`);

// Risk rows
const riskSection = prd.match(/#{1,3}\s+(?:\d+\.\s+)?Risk[\s\S]*?(?=\n#{1,3}\s|$)/i)?.[0] || '';
const riskRows = (riskSection.match(/\|[^|\n]+\|[^|\n]+\|[^|\n]+\|[^|\n]+\|/g) || []).filter(r => !r.includes('---') && !/likelihood/i.test(r));
if (riskRows.length < 2) errors.push(`Risk table has fewer than 2 risks (found ${riskRows.length})`);

// Compliance section check
if (fmMatch) {
  const fm = fmMatch[1];
  if (!/compliance:\s*none/i.test(fm) && fm.includes('compliance:') && !/#{1,3}\s+(?:\d+\.\s+)?Compliance/i.test(prd)) {
    errors.push('Section 8: Compliance Requirements required but missing (compliance != none in frontmatter)');
  }
}

if (errors.length > 0) {
  return [{ json: { valid: false, errors, project: data.project, version } }];
}

// Write handoff
fs.mkdirSync(`${data.workspacePath}/handoffs`, { recursive: true });
fs.writeFileSync(data.handoffPath, prd, 'utf8');

return [{
  json: {
    valid: true,
    errors: [],
    project: data.project,
    version,
    handoff_path: data.handoffPath,
    prd_path: prdPath
  }
}];

const fs = require('fs');
const data = $('Code - Validate Inputs').first().json;

// Load interview handoff (required)
let interviewContent;
try {
  interviewContent = fs.readFileSync(data.interviewHandoff, 'utf8');
} catch(e) {
  throw new Error(`Interview handoff not found at ${data.interviewHandoff}. Run Phase 2 (PRD Interview) first.`);
}

// Load analysis handoff (optional — greenfield projects have none)
let analysisContent = null;
try { analysisContent = fs.readFileSync(data.analysisHandoff, 'utf8'); } catch(e) {}

// Parse compliance flag from interview frontmatter
const fmMatch = interviewContent.match(/^---\n([\s\S]*?)\n---/);
let complianceApplicable = false;
if (fmMatch) {
  const fm = fmMatch[1];
  complianceApplicable = /compliance_applicable:\s*true/i.test(fm) ||
    (/compliance:/i.test(fm) && !/compliance:\s*none/i.test(fm) && !/compliance_applicable:\s*false/i.test(fm));
}

// Load current PRD for revision pass
let currentPrd = null;
if (data.currentVersion > 0) {
  const curPath = `${data.prdDir}/prd-${data.project}-v${data.currentVersion}.md`;
  try {
    currentPrd = fs.readFileSync(curPath, 'utf8');
  } catch(e) {
    throw new Error(`Current PRD v${data.currentVersion} not found at ${curPath}`);
  }
}

return [{
  json: {
    ...data,
    interviewContent,
    analysisContent,
    complianceApplicable,
    currentPrd
  }
}];

const fs = require('fs');
const data = $input.first().json;

// Load PRD writer system prompt (strip YAML frontmatter)
let writerPrompt = fs.readFileSync('/home/node/prompts/prd-development/prd-writer.md', 'utf8')
  .replace(/^---[\s\S]*?---\n/, '').trim();

// Always inject requirements engineering skill
let skills = fs.readFileSync('/home/node/skills/prd/requirements-engineering.md', 'utf8');

// Conditionally inject gov PRD skill when compliance applies
if (data.complianceApplicable) {
  skills += '\n\n---\n\n' + fs.readFileSync('/home/node/skills/prd/gov-prd-requirements.md', 'utf8');
}

return [{
  json: {
    ...data,
    systemPrompt: writerPrompt + '\n\n---\n\n' + skills
  }
}];

const data = $input.first().json;
const today = new Date().toISOString().split('T')[0];

let userMessage;

if (data.currentVersion === 0) {
  // Initial synthesis
  userMessage = `Please synthesize a complete PRD from the following materials.\n\nToday's date: ${today}\nProject name: ${data.project}\n\n## Interview Handoff\n${data.interviewContent}${data.analysisContent ? '\n\n## Analysis Handoff\n' + data.analysisContent : ''}\n\nProduce the full PRD with all required sections (1 through 7, plus section 8 only if compliance frameworks were identified). Begin with the YAML frontmatter block. Use version v1.`;
} else {
  // Revision pass
  userMessage = `Please revise the PRD based on this feedback.\n\nFeedback from reviewer:\n${data.feedback}\n\n## Current PRD (v${data.currentVersion})\n${data.currentPrd}\n\nApply the feedback precisely — don't invent changes not requested. Increment the version to v${data.version}. Add a brief "## Revision Notes (v${data.version})" section immediately after the frontmatter listing what changed and why.`;
}

return [{
  json: {
    ...data,
    messages: [
      { role: 'system', content: data.systemPrompt },
      { role: 'user', content: userMessage }
    ],
    model: 'qwen3.5:35b-a3b'
  }
}];

const ollamaResp = $input.first().json;
const buildData = $('Code - Build Synthesis Request').first().json;

const rawContent = ollamaResp.message?.content || ollamaResp.choices?.[0]?.message?.content || '';
if (!rawContent) throw new Error('Empty response from Ollama — check model availability and retry');

const version = buildData.version;
const project = buildData.project;
const today = new Date().toISOString().split('T')[0];

// Strip thinking block if present (model may emit thinking even with think:false)
let rawPrd = rawContent;
const thinkEnd = rawPrd.indexOf('</think>');
if (thinkEnd !== -1) {
  rawPrd = rawPrd.slice(thinkEnd + '</think>'.length).trim();
}

// Strip markdown code fence if model wrapped output in ```markdown
rawPrd = rawPrd.replace(/^```(?:markdown)?\n?/, '').replace(/\n?```\s*$/, '').trim();

let finalPrd = rawPrd;

// Ensure PRD has required frontmatter
if (!finalPrd.startsWith('---')) {
  const frontmatter = `---\nphase: prd-synthesis\nproject: ${project}\nversion: v${version}\ndate: ${today}\nstatus: Draft\nentry_point: greenfield\ncompliance: ${buildData.complianceApplicable ? 'applicable — see Section 8' : 'none'}\nsource_interview: ${buildData.interviewHandoff}\nsource_analysis: ${buildData.analysisContent ? buildData.analysisHandoff : 'none'}\n---\n\n`;
  finalPrd = frontmatter + finalPrd;
} else {
  // Update version and date in existing frontmatter
  finalPrd = finalPrd.replace(/version:\s*v\d+/, `version: v${version}`);
  finalPrd = finalPrd.replace(/date:\s*\S+/, `date: ${today}`);
  if (!/phase:\s*prd-synthesis/.test(finalPrd)) {
    finalPrd = finalPrd.replace('---\n', `---\nphase: prd-synthesis\n`);
  }
}

return [{
  json: {
    ...buildData,
    prdText: finalPrd,
    prdPath: `${buildData.prdDir}/prd-${project}-v${version}.md`,
    prdFilename: `prd-${project}-v${version}.md`
  }
}];

const fs = require('fs');
const path = require('path');
const data = $input.first().json;

// Write versioned PRD to tasks/
fs.mkdirSync(data.prdDir, { recursive: true });
fs.writeFileSync(data.prdPath, data.prdText, 'utf8');

// Also write to handoffs/003-prd-refined.md
const handoffDir = path.dirname(data.handoffPath);
fs.mkdirSync(handoffDir, { recursive: true });
fs.writeFileSync(data.handoffPath, data.prdText, 'utf8');

return [{
  json: {
    prd_text: data.prdText,
    version: data.version,
    project: data.project,
    prd_path: data.prdPath,
    handoff_path: data.handoffPath
  }
}];
